  "family": "Fries-, Photo-Fries, and Anionic Ortho-Fries Rearrangement",
  "candidate": {
    "substrate_smiles": [
      "CC(=O)Oc1ccccc1"
    ],
    "product_smiles": [
      "CC(=O)c1ccccc1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Al](Cl)Cl"
    ],
    "rationale": "The Fries rearrangement of phenyl acetate to 2-hydroxyacetophenone is a classic textbook example. It clearly demonstrates the core transformation: the migration of an acyl group from a phenolic oxygen to an ortho position on the aromatic ring, catalyzed by a Lewis acid (AlCl3). This example is simple, acyclic (except for the essential phenyl ring), and avoids complex substituents, making it an ideal canonical representation for this reaction family.",
    "collision_avoidance_note": "This example uses a simple phenyl acetate substrate to avoid overlap with reactions involving more complex polycyclic aromatic systems (e.g., Haworth reaction) or other functional groups. The transformation is a specific intramolecular rearrangement, distinct from intermolecular acylations (Friedel-Crafts acylation) or rearrangements not involving phenolic esters (e.g., Claisen rearrangement)."
  }
}
